import re
import zlib

def extract_pdf_content(filepath):
    '''More sophisticated PDF content extraction'''
    try:
        with open(filepath, 'rb') as f:
            content = f.read().decode('utf-8', errors='ignore')

        # Look for all streams
        streams = re.findall(r'stream\s*\n(.*?)\n\s*endstream', content, re.DOTALL)

        extracted_text = []
